package com.banking.security;

import android.content.Context;
import android.content.SharedPreferences;
import android.security.keystore.KeyGenParameterSpec;
import android.security.keystore.KeyProperties;

import androidx.security.crypto.EncryptedSharedPreferences;
import androidx.security.crypto.MasterKey;

import java.io.IOException;
import java.security.GeneralSecurityException;

public class SecureStorageManager {

    private static final String PREFS_FILE = "banking_secure_prefs";
    private SharedPreferences encryptedPrefs;

    public SecureStorageManager(Context context) throws GeneralSecurityException, IOException {
        KeyGenParameterSpec keySpec = new KeyGenParameterSpec.Builder(
                MasterKey.DEFAULT_MASTER_KEY_ALIAS,
                KeyProperties.PURPOSE_ENCRYPT | KeyProperties.PURPOSE_DECRYPT)
                .setBlockModes(KeyProperties.BLOCK_MODE_GCM)
                .setEncryptionPaddings(KeyProperties.ENCRYPTION_PADDING_NONE)
                .setKeySize(256)
                .setUserAuthenticationRequired(false) // Set true for biometric-gated access
                .build();

        MasterKey masterKey = new MasterKey.Builder(context)
                .setKeyGenParameterSpec(keySpec)
                .build();

        encryptedPrefs = EncryptedSharedPreferences.create(
                context,
                PREFS_FILE,
                masterKey,
                EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
                EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM
        );
    }

    public void storeSessionToken(String token) {
        encryptedPrefs.edit().putString("session_token", token).apply();
    }

    public String getSessionToken() {
        return encryptedPrefs.getString("session_token", null);
    }

    public void storeCachedBalance(String accountId, String encryptedBalance) {
        encryptedPrefs.edit().putString("balance_" + accountId, encryptedBalance).apply();
    }

    public String getCachedBalance(String accountId) {
        return encryptedPrefs.getString("balance_" + accountId, null);
    }

    public void clearAll() {
        encryptedPrefs.edit().clear().apply();
    }
}

