package com.banking.transaction;

import android.content.Context;
import android.util.Log;

import com.banking.model.Transaction;
import com.banking.security.DeviceIntegrityChecker;
import com.banking.security.SecureStorageManager;

import java.math.BigDecimal;

public class TransactionProcessor {

    private static final String TAG = "TransactionProcessor";
    private static final BigDecimal HIGH_VALUE_THRESHOLD = new BigDecimal("10000.00");

    private final Context context;
    private final DeviceIntegrityChecker integrityChecker;
    private final SecureStorageManager secureStorage;

    public interface TransactionCallback {
        void onTransactionSuccess(Transaction transaction);
        void onTransactionFailed(Transaction transaction, String reason);
        void onIntegrityCheckFailed(String reason);
    }

    public TransactionProcessor(Context context) throws Exception {
        this.context = context.getApplicationContext();
        this.integrityChecker = new DeviceIntegrityChecker(context);
        this.secureStorage = new SecureStorageManager(context);
    }

    /**
     * Process a financial transaction with full integrity verification.
     * High-value transactions trigger additional Play Integrity API checks.
     */
    public void processTransaction(Transaction transaction, TransactionCallback callback) {
        Log.i(TAG, "Processing transaction: " + transaction.getTransactionId());

        // Validate transaction parameters first
        String validationError = validateTransaction(transaction);
        if (validationError != null) {
            transaction.setStatus(Transaction.TransactionStatus.FAILED);
            transaction.setFailureReason(validationError);
            callback.onTransactionFailed(transaction, validationError);
            return;
        }

        // For all transactions, perform integrity check
        if (isHighValueTransaction(transaction)) {
            // High-value transactions require full integrity check including Play Integrity API
            performFullIntegrityCheckAndProcess(transaction, callback);
        } else {
            // Standard transactions use local integrity checks for speed,
            // but still verify device state
            performLocalIntegrityCheckAndProcess(transaction, callback);
        }
    }

    private void performFullIntegrityCheckAndProcess(Transaction transaction, TransactionCallback callback) {
        integrityChecker.performFullIntegrityCheck((isDeviceTrusted, reason) -> {
            if (!isDeviceTrusted) {
                Log.w(TAG, "Full integrity check failed: " + reason);
                transaction.setStatus(Transaction.TransactionStatus.BLOCKED_INTEGRITY);
                transaction.setFailureReason("Transaction blocked: " + reason);
                callback.onIntegrityCheckFailed(reason);
                return;
            }

            Log.i(TAG, "Full integrity check passed. Processing high-value transaction.");
            executeTransaction(transaction, callback);
        });
    }

    private void performLocalIntegrityCheckAndProcess(Transaction transaction, TransactionCallback callback) {
        boolean localCheckPassed = integrityChecker.performLocalIntegrityCheck();

        if (!localCheckPassed) {
            Log.w(TAG, "Local integrity check failed for transaction: " + transaction.getTransactionId());
            transaction.setStatus(Transaction.TransactionStatus.BLOCKED_INTEGRITY);
            transaction.setFailureReason("Transaction blocked due to device integrity concerns");
            callback.onIntegrityCheckFailed("Device integrity check failed. " +
                    "Please ensure your device is not rooted or compromised.");
            return;
        }

        Log.i(TAG, "Local integrity check passed. Processing transaction.");
        executeTransaction(transaction, callback);
    }

    private void executeTransaction(Transaction transaction, TransactionCallback callback) {
        // In production, this would make a secure API call to the banking backend
        // The server should also independently verify device integrity using the token
        try {
            String sessionToken = secureStorage.getSessionToken();
            if (sessionToken == null || sessionToken.isEmpty()) {
                transaction.setStatus(Transaction.TransactionStatus.FAILED);
                transaction.setFailureReason("No valid session. Please log in again.");
                callback.onTransactionFailed(transaction, "Authentication required");
                return;
            }

            // Simulate API call to backend
            // In production: Use OkHttp/Retrofit with certificate pinning
            boolean serverResult = sendTransactionToServer(transaction, sessionToken);

            if (serverResult) {
                transaction.setStatus(Transaction.TransactionStatus.COMPLETED);
                callback.onTransactionSuccess(transaction);
            } else {
                transaction.setStatus(Transaction.TransactionStatus.FAILED);
                transaction.setFailureReason("Server rejected the transaction");
                callback.onTransactionFailed(transaction, "Transaction was declined by the server");
            }
        } catch (Exception e) {
            Log.e(TAG, "Transaction execution error", e);
            transaction.setStatus(Transaction.TransactionStatus.FAILED);
            transaction.setFailureReason("Processing error: " + e.getMessage());
            callback.onTransactionFailed(transaction, "An error occurred processing your transaction");
        }
    }

    private boolean sendTransactionToServer(Transaction transaction, String sessionToken) {
        // TODO: Implement actual secure API call with:
        // - TLS 1.3 with certificate pinning
        // - Request signing
        // - Integrity token forwarding for server-side verification
        // - Idempotency key (transaction ID)

        // Placeholder for demonstration
        return true;
    }

    private String validateTransaction(Transaction transaction) {
        if (transaction.getAmount() == null || transaction.getAmount().compareTo(BigDecimal.ZERO) <= 0) {
            return "Transaction amount must be positive";
        }
        if (transaction.getFromAccountId() == null || transaction.getFromAccountId().isEmpty()) {
            return "Source account is required";
        }
        if (transaction.getType() == Transaction.TransactionType.TRANSFER
                && (transaction.getToAccountId() == null || transaction.getToAccountId().isEmpty())) {
            return "Destination account is required for transfers";
        }
        if (transaction.getAmount().scale() > 2) {
            return "Amount cannot have more than 2 decimal places";
        }
        return null;
    }

    private boolean isHighValueTransaction(Transaction transaction) {
        return transaction.getAmount().compareTo(HIGH_VALUE_THRESHOLD) >= 0;
    }
}

