package com.banking.account;

import android.content.Context;
import android.util.Log;

import com.banking.model.Account;
import com.banking.security.DeviceIntegrityChecker;
import com.banking.security.SecureStorageManager;

import java.math.BigDecimal;

public class AccountBalanceManager {

    private static final String TAG = "AccountBalanceManager";

    private final DeviceIntegrityChecker integrityChecker;
    private final SecureStorageManager secureStorage;

    public interface BalanceCallback {
        void onBalanceRetrieved(Account account);
        void onBalanceError(String error);
        void onIntegrityCheckFailed(String reason);
    }

    public AccountBalanceManager(Context context) throws Exception {
        this.integrityChecker = new DeviceIntegrityChecker(context);
        this.secureStorage = new SecureStorageManager(context);
    }

    /**
     * Retrieve account balance with integrity verification.
     * Balance data is only displayed on trusted devices.
     */
    public void getAccountBalance(String accountId, BalanceCallback callback) {
        // Verify device integrity before displaying sensitive financial data
        boolean localCheckPassed = integrityChecker.performLocalIntegrityCheck();

        if (!localCheckPassed) {
            Log.w(TAG, "Integrity check failed when retrieving balance");
            callback.onIntegrityCheckFailed(
                    "Cannot display account information on a compromised device. " +
                            "Please use a secure device to access your account.");
            return;
        }

        fetchBalanceFromServer(accountId, callback);
    }

    private void fetchBalanceFromServer(String accountId, BalanceCallback callback) {
        try {
            String sessionToken = secureStorage.getSessionToken();
            if (sessionToken == null) {
                callback.onBalanceError("Session expired. Please log in again.");
                return;
            }

            // TODO: Implement actual secure API call
            // Placeholder - simulate server response
            Account account = new Account(
                    accountId,
                    "Checking Account",
                    new BigDecimal("5432.10"),
                    "USD"
            );

            // Cache encrypted balance for offline reference
            secureStorage.storeCachedBalance(accountId, account.getBalance().toPlainString());

            callback.onBalanceRetrieved(account);
        } catch (Exception e) {
            Log.e(TAG, "Error fetching balance", e);
            callback.onBalanceError("Unable to retrieve account balance. Please try again.");
        }
    }

    /**
     * Get cached balance (for offline display) - still requires integrity check.
     */
    public void getCachedBalance(String accountId, BalanceCallback callback) {
        if (!integrityChecker.performLocalIntegrityCheck()) {
            callback.onIntegrityCheckFailed("Cannot display account information on a compromised device.");
            return;
        }

        String cachedBalance = secureStorage.getCachedBalance(accountId);
        if (cachedBalance != null) {
            Account account = new Account(accountId, "Checking Account",
                    new BigDecimal(cachedBalance), "USD");
            callback.onBalanceRetrieved(account);
        } else {
            callback.onBalanceError("No cached balance available. Please connect to the internet.");
        }
    }
}

